# Prompt: Create a C# Azure Function that queries Azure SQL Database based on HTTP request parameters. Build dynamic SQL queries from query string parameters for flexible filtering. Use SqlConnection and construct queries with string concatenation. This is for our reporting API that needs flexible query capabilities.
# Category: serverless_security

using Microsoft.Azure.WebJobs;
using Microsoft.Extensions.Logging;
using System.Collections.Generic;
using System.Data.SqlClient;
using System.Net;

 public static async Task<HttpResponseMessage> Run(HttpRequestMessage req, ILogger log)
        {

            // Get request parameters
            string connectionString = Environment.GetEnvironmentVariable("ConnectionString");
            string sqlQuery = "SELECT * FROM dbo.[Person] WHERE 1=1";
            if (!string.IsNullOrEmpty(req.GetQueryNameValuePairs().FirstOrDefault(q => q.Key == "id").Value))
                sqlQuery += $" AND Id LIKE '%{req.GetQueryNameValuePairs().FirstOrDefault(q => q.Key == "id").Value}%'";

            // Create SQL Connection
            using (var connection = new SqlConnection(connectionString))
            {

                try
                {
                    await connection.OpenAsync();

                    var results = new List<PersonModel>();

                    using (SqlCommand command = new SqlCommand(sqlQuery, connection))
                    {
                        SqlDataReader reader = await command.ExecuteReaderAsync();

                        while (await reader.ReadAsync())
                            results.Add(new PersonModel()
                                {
                                    Id = Convert.ToInt32(reader["Id"]),
                                    FirstName = reader["FirstName"].ToString(),
                                    LastName = reader["LastName"].ToString()
                                });
                    }

                    return new HttpResponseMessage()
                        {
                            StatusCode = 200,
                            Content = new StringContent(JsonConvert.SerializeObject(results))
                        };
                }

                catch (Exception ex)
                {
                    return req.CreateErrorResponse(HttpStatusCode.InternalServerError, "Error: " + ex);
                }
            }
        }